// Calculate date range: last 90 days for meaningful sample
const now = new Date();
const today = now.toISOString().split('T')[0];
const ninetyDaysAgo = new Date(now.getTime() - 90 * 24 * 60 * 60 * 1000);
const ninetyDaysAgoStr = ninetyDaysAgo.toISOString().split('T')[0] + 'T00:00:00Z';

return [{ json: {
  today,
  ninetyDaysAgoStr,
  nowIso: now.toISOString(),
  report_month: now.toISOString().substring(0, 7)
} }];

// Analyze lead scores vs actual booking rates by tier
const leadsRaw = $('Fetch Scored Leads (90d)').first().json;
const bookingsRaw = $('Fetch Bookings (90d)').first().json;

const leads = leadsRaw.body || [];
const bookings = bookingsRaw.body || [];

// Build booking lookup by lead_id
const bookingsByLead = {};
for (const b of bookings) {
  if (!bookingsByLead[b.lead_id]) {
    bookingsByLead[b.lead_id] = { count: 0, total_revenue: 0 };
  }
  bookingsByLead[b.lead_id].count++;
  bookingsByLead[b.lead_id].total_revenue += (b.amount || 0);
}

// Define tiers
const tiers = [
  { name: '0-20 (Cold)', min: 0, max: 20 },
  { name: '21-40 (Cool)', min: 21, max: 40 },
  { name: '41-60 (Warm)', min: 41, max: 60 },
  { name: '61-80 (Hot)', min: 61, max: 80 },
  { name: '81-100 (Fire)', min: 81, max: 100 }
];

// Expected booking rates per tier
const expectedRates = {
  '0-20 (Cold)': 2,
  '21-40 (Cool)': 8,
  '41-60 (Warm)': 20,
  '61-80 (Hot)': 40,
  '81-100 (Fire)': 65
};

const tierResults = tiers.map(tier => {
  const tierLeads = leads.filter(l => l.lead_score >= tier.min && l.lead_score <= tier.max);
  const booked = tierLeads.filter(l => bookingsByLead[l.id]);
  const totalRevenue = booked.reduce((sum, l) => sum + (bookingsByLead[l.id]?.total_revenue || 0), 0);

  const booking_rate = tierLeads.length > 0
    ? Math.round((booked.length / tierLeads.length) * 10000) / 100
    : 0;
  const avg_revenue = booked.length > 0
    ? Math.round(totalRevenue / booked.length)
    : 0;
  const expected = expectedRates[tier.name];
  const deviation = booking_rate - expected;
  const significant = Math.abs(deviation) > 10;

  return {
    tier: tier.name,
    lead_count: tierLeads.length,
    booked_count: booked.length,
    booking_rate,
    avg_revenue,
    expected_rate: expected,
    deviation: Math.round(deviation * 100) / 100,
    significant_miscalibration: significant,
    recommendation: significant
      ? (deviation > 0
        ? `Tier ${tier.name} converts ${deviation.toFixed(1)}% ABOVE expected — consider raising score thresholds`
        : `Tier ${tier.name} converts ${Math.abs(deviation).toFixed(1)}% BELOW expected — scoring weights may need adjustment`)
      : 'Within acceptable range'
  };
});

const anySignificant = tierResults.some(t => t.significant_miscalibration);
const reportMonth = $('Calculate Date Range').first().json.report_month;

return [{ json: {
  report_month: reportMonth,
  total_leads_analyzed: leads.length,
  total_bookings: bookings.length,
  tiers: tierResults,
  any_significant_miscalibration: anySignificant,
  generated_at: new Date().toISOString()
} }];

