// Build alert HTML for miscalibrated tiers
const data = $('Analyze Score Tiers').item.json;
const miscalibrated = data.tiers.filter(t => t.significant_miscalibration);

const tierRows = miscalibrated.map(t =>
  `<tr><td>${t.tier}</td><td>${t.lead_count}</td><td>${t.booking_rate}%</td><td>${t.expected_rate}%</td><td style="color:${t.deviation > 0 ? 'green' : 'red'}">${t.deviation > 0 ? '+' : ''}${t.deviation}%</td><td>${t.recommendation}</td></tr>`
).join('');

const html = `<p>Monthly lead score calibration detected <strong>${miscalibrated.length}</strong> miscalibrated tier(s).</p>
<table border="1" cellpadding="4" style="border-collapse:collapse">
<tr><th>Tier</th><th>Leads</th><th>Actual Rate</th><th>Expected</th><th>Deviation</th><th>Recommendation</th></tr>
${tierRows}
</table>
<p><em>Analysis based on ${data.total_leads_analyzed} leads over 90 days. This is a recommendation only — no automatic changes were made.</em></p>`;

return [{ json: {
  alert_type: 'lead_score_calibration',
  alert_title: 'Lead Score Miscalibration Detected — ' + data.report_month,
  alert_body: html,
  severity: 'warning',
  source_workflow: 'TG-124',
  metadata: JSON.stringify({ miscalibrated_tiers: miscalibrated.length, report_month: data.report_month })
} }];
